<template><view class="page"><view class="title">自定义内容</view><AppCard title="自定义问答"><view v-for="x in qas" :key="x.id" class="list-item">{{x.question}} → {{x.answerText||'录音答案'}}</view><button class="btn" @click="addQa">新增示例问答</button></AppCard><AppCard title="故事与儿歌"><view v-for="x in contents" :key="x.id" class="list-item">{{x.title}} · {{x.auditStatus}}</view><button class="btn" @click="addContent">上传示例故事</button></AppCard></view></template><script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import AppCard from'@/components/AppCard.vue';import{qingxierApi}from'@/services/api';import{useDeviceStore}from'@/stores/device';const qas=ref<any[]>([]),contents=ref<any[]>([]),d=useDeviceStore();async function load(){await d.load();[qas.value,contents.value]=await Promise.all([qingxierApi.customQas(),qingxierApi.customContents()])}onShow(load);async function addQa(){await qingxierApi.addQa({deviceId:d.currentId,question:'妈妈的生日？',answerText:'5月20日'});await load()}async function addContent(){await qingxierApi.addContent({deviceId:d.currentId,type:'story',title:'妈妈的故事',audioUrl:'https://cdn.example.com/story.mp3',duration:180});await load()}</script>
